import type { Metadata } from "next";
import DischargeSummary from "./DischargeSummary";

export const metadata: Metadata = {
  title: "退院サマリ / 退院時要約 | ぐんじょう 電子カルテ",
  description:
    "医師が入院の最後に退院サマリ（退院時要約）を作成・確定・署名する画面。患者・入院コンテキスト（患者ID / 氏名 / 年齢・性別 / 入院日・退院日 / 在院日数 / 診療科 / 主治医）の上で、主病名・既往歴・入院時現症・入院の経過・実施した検査/治療/手術・退院時の状態/転帰・退院時処方・退院後の方針/フォローアップ・紹介元/紹介先を構造化して記載する。下書き中は各セクションを編集でき、署名・確定すると本文は変更不可の法的記録となり、以後は追記（addendum：記録者・タイムスタンプ・理由つき）のみ追加できる。研修医が作成した場合は指導医の共同署名（CoSign）で正式となる。",
};

export default function DischargeSummaryPage() {
  return <DischargeSummary />;
}

// 退院サマリ / 退院時要約 — data model & seed data.
//
// The defining 作法 of this screen: the discharge summary is drafted, then
// 署名・確定 (signed) — at which point the body becomes an append-only legal
// record. Once signed it can never be edited; the only way to change anything
// is an 追記 (addendum), each with its own author + timestamp + reason.
//
// NOTE (FINDINGS-59): the sign→lock→addendum-only shape below is hand-rolled.
// It is the 3rd screen (#57 nursing, #58 operative, now #59) to re-implement the
// same SignedRecord/AppendOnlyRecord state machine — @gunjo/ui ships no primitive.

export interface Patient {
  patientId: string;
  name: string;
  kana: string;
  age: number;
  sex: "男性" | "女性";
  admittedAt: string; // ISO date
  dischargedAt: string; // ISO date
  department: string;
  attending: string; // 主治医
  resident?: string; // 研修医 (drafting clinician, if a trainee)
}

/** 退院時転帰 (discharge outcome). */
export type Outcome = "治癒" | "軽快" | "不変" | "増悪" | "死亡";

/** The labelled body sections of the structured discharge summary. */
export interface SummaryDraft {
  principalDiagnosis: string; // 主病名
  comorbidities: string; // 既往歴・合併症
  admissionFindings: string; // 入院時現症
  course: string; // 入院の経過（本文）
  procedures: string; // 実施した検査・治療・手術
  outcome: Outcome | ""; // 退院時の状態・転帰
  dischargeCondition: string; // 退院時の状態（補足）
  dischargeMeds: string; // 退院時処方（フリーテキスト補足）
  followUp: string; // 退院後の方針・フォローアップ予定
  referral: string; // 紹介元・紹介先
}

/** Which body sections are required before the summary can be signed. */
export const REQUIRED_SECTIONS: {
  key: keyof SummaryDraft;
  label: string;
}[] = [
  { key: "principalDiagnosis", label: "主病名" },
  { key: "admissionFindings", label: "入院時現症" },
  { key: "course", label: "入院の経過" },
  { key: "outcome", label: "退院時の状態・転帰" },
  { key: "followUp", label: "退院後の方針・フォローアップ予定" },
];

/** 退院時の主要検査値 (discharge lab values, judged vs reference range). */
export interface DischargeLab {
  id: string;
  name: string;
  value: number;
  unit: string;
  low?: number;
  high?: number;
  criticalLow?: number;
  criticalHigh?: number;
}

/** 退院時処方 (structured discharge prescription line). */
export interface DischargeMed {
  id: string;
  name: string;
  dose: string;
  freq: string;
  days: string;
}

export interface Appointment {
  id: string;
  date: string; // ISO date
  department: string;
  note: string;
}

/** 追記 (addendum) — append-only, each with its own author + timestamp + reason. */
export interface Addendum {
  id: string;
  author: string;
  at: string; // ISO datetime
  reason: string;
  body: string;
}

export const patient: Patient = {
  patientId: "P-0048213",
  name: "佐藤 健一",
  kana: "サトウ ケンイチ",
  age: 68,
  sex: "男性",
  admittedAt: "2026-06-08",
  dischargedAt: "2026-06-22",
  department: "循環器内科",
  attending: "中村 和彦",
  resident: "研修医 大野 翔",
};

export const initialDraft: SummaryDraft = {
  principalDiagnosis: "急性心不全（HFrEF, EF 32%）／拡張型心筋症の急性増悪",
  comorbidities: "高血圧症、2型糖尿病、慢性腎臓病（G3a）、脂質異常症",
  admissionFindings:
    "労作時呼吸困難および両下腿浮腫を主訴に救急外来受診。起座呼吸あり。両肺野に湿性ラ音、頸静脈怒張を認め、胸部X線で肺うっ血・心拡大を認めた。BNP 高値。NYHA III度。",
  course:
    "入院当日より酸素投与・利尿薬（フロセミド静注）を開始し、うっ血は速やかに改善。第3病日よりACE阻害薬・β遮断薬を導入し漸増。心エコーでEF 32%、びまん性壁運動低下を確認。第10病日にはNYHA II度まで改善し、内服へ移行のうえ体重も安定。リハビリ介入により病棟内歩行自立。",
  procedures:
    "心電図、胸部X線、経胸壁心エコー（EF 32%）、心臓MRI、血液検査（BNP, 腎機能, 電解質）。冠動脈CTで有意狭窄なし。フロセミド静注→内服切替、ACE阻害薬・β遮断薬・MRA導入。",
  outcome: "軽快",
  dischargeCondition:
    "NYHA II度。安静時呼吸困難なし、下腿浮腫消失。体重 62.4kg で安定。退院時SpO2 97%（室内気）。",
  dischargeMeds:
    "下記「退院時処方」リスト参照。塩分制限（6g/日未満）・水分管理の指導済み。",
  followUp:
    "2週間後に循環器内科外来で再診（体重・浮腫・腎機能フォロー）。心リハ継続。体重が3日で2kg以上増加した場合は受診を指示。",
  referral:
    "紹介元：かかりつけ さくら内科クリニック（高血圧・糖尿病の継続管理）。退院後はクリニックと当科で併診。",
};

export const dischargeLabs: DischargeLab[] = [
  { id: "bnp", name: "BNP", value: 142, unit: "pg/mL", high: 18.4, criticalHigh: 500 },
  { id: "egfr", name: "eGFR", value: 48, unit: "mL/min", low: 60, criticalLow: 30 },
  { id: "k", name: "K（カリウム）", value: 4.6, unit: "mEq/L", low: 3.5, high: 5.0, criticalHigh: 6.0, criticalLow: 3.0 },
  { id: "na", name: "Na（ナトリウム）", value: 139, unit: "mEq/L", low: 135, high: 145 },
  { id: "hb", name: "Hb", value: 11.8, unit: "g/dL", low: 13.0, high: 17.0 },
  { id: "cr", name: "Cr（クレアチニン）", value: 1.32, unit: "mg/dL", low: 0.6, high: 1.1, criticalHigh: 4.0 },
];

export const dischargeMeds: DischargeMed[] = [
  { id: "m1", name: "エナラプリル錠 2.5mg", dose: "1回1錠", freq: "1日1回 朝食後", days: "30日分" },
  { id: "m2", name: "ビソプロロール錠 2.5mg", dose: "1回1錠", freq: "1日1回 朝食後", days: "30日分" },
  { id: "m3", name: "スピロノラクトン錠 25mg", dose: "1回1錠", freq: "1日1回 朝食後", days: "30日分" },
  { id: "m4", name: "フロセミド錠 20mg", dose: "1回1錠", freq: "1日1回 朝食後", days: "30日分" },
  { id: "m5", name: "ダパグリフロジン錠 10mg", dose: "1回1錠", freq: "1日1回 朝食後", days: "30日分" },
];

export const appointments: Appointment[] = [
  { id: "a1", date: "2026-07-06", department: "循環器内科", note: "再診（体重・浮腫・腎機能・BNP フォロー）" },
  { id: "a2", date: "2026-07-13", department: "心臓リハビリ", note: "外来心リハ 初回" },
];

/** Seed addenda — empty at first; populated as the user 追記 after signing. */
export const initialAddenda: Addendum[] = [];

export function daysBetween(fromISO: string, toISO: string): number {
  const from = new Date(fromISO + "T00:00:00");
  const to = new Date(toISO + "T00:00:00");
  const ms = to.getTime() - from.getTime();
  return Math.round(ms / 86_400_000) + 1; // inclusive of admit & discharge day
}

export function formatDate(iso: string): string {
  const d = new Date((iso.length <= 10 ? iso + "T00:00:00" : iso));
  return `${d.getFullYear()}年${d.getMonth() + 1}月${d.getDate()}日`;
}

export function formatDateTime(iso: string): string {
  const d = new Date(iso);
  const hh = String(d.getHours()).padStart(2, "0");
  const mm = String(d.getMinutes()).padStart(2, "0");
  return `${d.getFullYear()}/${d.getMonth() + 1}/${d.getDate()} ${hh}:${mm}`;
}

/** Outcome → semantic tone (治癒/軽快 = success, 不変 = info, 増悪 = warning, 死亡 = destructive). */
export function outcomeTone(o: Outcome | ""): "success" | "info" | "warning" | "destructive" | "outline" {
  switch (o) {
    case "治癒":
    case "軽快":
      return "success";
    case "不変":
      return "info";
    case "増悪":
      return "warning";
    case "死亡":
      return "destructive";
    default:
      return "outline";
  }
}

export const OUTCOMES: Outcome[] = ["治癒", "軽快", "不変", "増悪", "死亡"];

"use client";

import * as React from "react";
import {
  IconUser,
  IconCalendarEvent,
  IconStethoscope,
  IconBuildingHospital,
  IconLock,
  IconLockOpen,
  IconSignature,
  IconPlus,
  IconWriting,
  IconCircleCheck,
  IconAlertTriangle,
  IconPrinter,
  IconFileText,
  IconCornerDownRight,
  IconClipboardText,
  IconFlask,
  IconPill,
  IconCalendarClock,
  IconChevronRight,
  type TablerIcon,
} from "@tabler/icons-react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
  CoSign,
  CoSignBadge,
  type CoSignValue,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormLabel,
  MetadataList,
  ReferenceValue,
  Select,
  Separator,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
  Textarea,
  Timeline,
  TimelineItem,
  TimelineTime,
  TimelineTitle,
  TimelineDescription,
} from "@gunjo/ui";
import {
  patient,
  initialDraft,
  initialAddenda,
  dischargeLabs,
  dischargeMeds,
  appointments,
  REQUIRED_SECTIONS,
  OUTCOMES,
  daysBetween,
  formatDate,
  formatDateTime,
  outcomeTone,
  type SummaryDraft,
  type Addendum,
  type Outcome,
} from "./data";

/* ── current signed-in clinicians (would come from the session) ───────────── */
const CURRENT_USER = patient.resident ?? patient.attending; // drafting clinician
const ATTENDING_ID = patient.attending; // 指導医 / 主治医 who must co-sign
const RESIDENT_DRAFTING = Boolean(patient.resident); // resident → needs attending co-sign

/* ── helper: live ISO timestamp generated only on the client (no hydration risk
 *    because all timestamps are produced inside event handlers, never on render) */
function nowISO(): string {
  return new Date().toISOString();
}

/* ───────────────────────── section definitions ──────────────────────────── */
interface SectionDef {
  key: keyof SummaryDraft;
  label: string;
  description?: string;
  rows?: number;
  /** outcome is a Select, not a textarea */
  kind?: "text" | "outcome";
}

const SECTIONS: SectionDef[] = [
  { key: "principalDiagnosis", label: "主病名", description: "今回の入院の主たる病名（ICD想定）。", rows: 2 },
  { key: "comorbidities", label: "既往歴・合併症", rows: 2 },
  { key: "admissionFindings", label: "入院時現症", description: "入院時の主訴・身体所見。", rows: 3 },
  { key: "course", label: "入院の経過（本文）", description: "入院から退院までの臨床経過。", rows: 6 },
  { key: "procedures", label: "実施した検査・治療・手術", rows: 4 },
  { key: "outcome", label: "退院時の状態・転帰", description: "治癒／軽快／不変／増悪／死亡 から選択。", kind: "outcome" },
  { key: "dischargeCondition", label: "退院時の状態（補足）", rows: 2 },
  { key: "dischargeMeds", label: "退院時処方（補足）", description: "下の「退院時処方」表に加える補足・指導。", rows: 2 },
  { key: "followUp", label: "退院後の方針・フォローアップ予定", rows: 3 },
  { key: "referral", label: "紹介元・紹介先", rows: 2 },
];

const REQUIRED_KEYS = new Set(REQUIRED_SECTIONS.map((s) => s.key));

/* ───────────────────────── small presentational bits ────────────────────── */
function HeaderFact({ icon: Icon, label, children }: { icon: TablerIcon; label: string; children: React.ReactNode }) {
  return (
    <div className="flex min-w-0 items-start gap-2">
      <Icon className="mt-0.5 h-4 w-4 shrink-0 text-muted-foreground" aria-hidden />
      <div className="min-w-0">
        <dt className="text-xs text-muted-foreground">{label}</dt>
        <dd className="truncate text-sm font-medium text-foreground">{children}</dd>
      </div>
    </div>
  );
}

/* read-only rendering of one section's value (preserves line breaks) */
function SectionReadValue({ value }: { value: string }) {
  if (!value.trim()) return <p className="text-sm italic text-muted-foreground">（記載なし）</p>;
  return <p className="whitespace-pre-wrap text-sm leading-relaxed text-foreground">{value}</p>;
}

/* ───────────────────────────── main component ───────────────────────────── */
export default function DischargeSummary() {
  const los = daysBetween(patient.admittedAt, patient.dischargedAt);

  // ── the signed-record state machine (HAND-ROLLED — see FINDINGS-59) ──
  const [draft, setDraft] = React.useState<SummaryDraft>(initialDraft);
  const [status, setStatus] = React.useState<"draft" | "signed">("draft");
  const [signedBy, setSignedBy] = React.useState<string | null>(null);
  const [signedAt, setSignedAt] = React.useState<string | null>(null);
  const [coSign, setCoSign] = React.useState<CoSignValue | undefined>(undefined);
  const [addenda, setAddenda] = React.useState<Addendum[]>(initialAddenda);

  const signed = status === "signed";
  // a resident's summary is not "official" until the attending co-signs
  const official = signed && (!RESIDENT_DRAFTING || Boolean(coSign));

  // ── required-section gating for signing ──
  const missing = REQUIRED_SECTIONS.filter((s) => !String(draft[s.key]).trim());
  const canSign = missing.length === 0;

  // ── dialogs ──
  const [signOpen, setSignOpen] = React.useState(false);
  const [addOpen, setAddOpen] = React.useState(false);
  const [addReason, setAddReason] = React.useState("");
  const [addBody, setAddBody] = React.useState("");

  const updateSection = (key: keyof SummaryDraft, value: string) => {
    if (signed) return; // immutable once signed — guard at the state layer too
    setDraft((d) => ({ ...d, [key]: value }));
  };

  const handleSign = () => {
    if (!canSign) return;
    setStatus("signed");
    setSignedBy(CURRENT_USER);
    setSignedAt(nowISO());
    setSignOpen(false);
  };

  const handleAddAddendum = () => {
    const reason = addReason.trim();
    const body = addBody.trim();
    if (!reason || !body) return;
    setAddenda((prev) => [
      ...prev,
      { id: `ad-${prev.length + 1}-${Date.now()}`, author: CURRENT_USER, at: nowISO(), reason, body },
    ]);
    setAddReason("");
    setAddBody("");
    setAddOpen(false);
  };

  const statusBadge = signed ? (
    official ? (
      <Badge variant="success">
        <IconCircleCheck className="mr-1 h-3.5 w-3.5" aria-hidden />
        署名・確定済
      </Badge>
    ) : (
      <Badge variant="warning">
        <IconAlertTriangle className="mr-1 h-3.5 w-3.5" aria-hidden />
        指導医の共同署名待ち
      </Badge>
    )
  ) : (
    <Badge variant="info">
      <IconWriting className="mr-1 h-3.5 w-3.5" aria-hidden />
      下書き
    </Badge>
  );

  return (
    <main className="mx-auto w-full max-w-5xl px-4 py-6 sm:px-6 lg:py-10">
      {/* ── page title ── */}
      <div className="mb-4 flex flex-wrap items-center gap-x-3 gap-y-2">
        <h1 className="text-xl font-bold tracking-tight text-foreground sm:text-2xl">退院サマリ / 退院時要約</h1>
        {statusBadge}
        {signed && RESIDENT_DRAFTING ? <CoSignBadge value={coSign} signedLabel="指導医 共同署名 済" pendingLabel="指導医 共同署名 要" /> : null}
      </div>

      {/* ── lock state, conveyed by text + icon (not colour alone) ── */}
      {signed ? (
        <Alert variant="success" className="mb-5">
          <IconLock className="h-4 w-4" aria-hidden />
          <AlertTitle as="p">この退院サマリは確定済みです（編集不可）</AlertTitle>
          <AlertDescription>
            {signedBy} が {signedAt ? formatDateTime(signedAt) : "—"} に署名・確定しました。本文は法的記録として変更できません。修正・補足は「追記（addendum）」で行ってください。
            {RESIDENT_DRAFTING && !official ? " 研修医が作成したため、指導医の共同署名が完了するまで正式な記録になりません。" : ""}
          </AlertDescription>
        </Alert>
      ) : (
        <Alert variant="info" className="mb-5">
          <IconWriting className="h-4 w-4" aria-hidden />
          <AlertTitle as="p">下書き作成中</AlertTitle>
          <AlertDescription>
            各セクションを記載してください。「署名・確定」すると本文はロックされ、以後は追記でのみ修正できます。
          </AlertDescription>
        </Alert>
      )}

      {/* ── 患者・入院コンテキスト ── */}
      <Card className="mb-5">
        <CardHeader className="pb-3">
          <CardTitle as="h2" className="flex items-center gap-2 text-base">
            <IconUser className="h-4 w-4 text-muted-foreground" aria-hidden />
            患者・入院情報
          </CardTitle>
        </CardHeader>
        <CardContent>
          <dl className="grid grid-cols-2 gap-x-4 gap-y-3 sm:grid-cols-3 lg:grid-cols-4">
            <HeaderFact icon={IconUser} label="患者ID">{patient.patientId}</HeaderFact>
            <HeaderFact icon={IconUser} label="氏名">
              {patient.name}
              <span className="ml-1 text-xs font-normal text-muted-foreground">（{patient.kana}）</span>
            </HeaderFact>
            <HeaderFact icon={IconUser} label="年齢・性別">{patient.age}歳 / {patient.sex}</HeaderFact>
            <HeaderFact icon={IconBuildingHospital} label="診療科">{patient.department}</HeaderFact>
            <HeaderFact icon={IconCalendarEvent} label="入院日">{formatDate(patient.admittedAt)}</HeaderFact>
            <HeaderFact icon={IconCalendarEvent} label="退院日">{formatDate(patient.dischargedAt)}</HeaderFact>
            <HeaderFact icon={IconCalendarClock} label="在院日数">{los}日</HeaderFact>
            <HeaderFact icon={IconStethoscope} label="主治医">{patient.attending}</HeaderFact>
            {patient.resident ? (
              <HeaderFact icon={IconWriting} label="作成（研修医）">{patient.resident}</HeaderFact>
            ) : null}
          </dl>
        </CardContent>
      </Card>

      {/* ── required-sections checklist while drafting ── */}
      {!signed && missing.length > 0 ? (
        <Alert variant="warning" className="mb-5">
          <IconAlertTriangle className="h-4 w-4" aria-hidden />
          <AlertTitle as="p">署名前に必須セクションの記載が必要です</AlertTitle>
          <AlertDescription>
            未記載：{missing.map((m) => m.label).join(" / ")}
          </AlertDescription>
        </Alert>
      ) : null}

      {/* ── サマリ本文（構造化セクション）── */}
      <Card className="mb-5">
        <CardHeader className="pb-3">
          <CardTitle as="h2" className="flex items-center gap-2 text-base">
            <IconClipboardText className="h-4 w-4 text-muted-foreground" aria-hidden />
            サマリ本文
          </CardTitle>
          <CardDescription>
            {signed ? "確定済みの本文（読み取り専用）。" : "入院経過の構造化された要約。下書き中は編集できます。"}
          </CardDescription>
        </CardHeader>
        <CardContent>
          {signed ? (
            // ── SIGNED: read-only snapshot, programmatically conveyed ──
            <dl className="divide-y divide-border" aria-readonly="true">
              {SECTIONS.map((s) => (
                <div key={s.key} className="grid grid-cols-1 gap-1 py-3 sm:grid-cols-[12rem_1fr] sm:gap-4">
                  <dt className="flex items-center gap-1.5 text-sm font-semibold text-foreground">
                    {s.label}
                    {REQUIRED_KEYS.has(s.key) ? <span className="text-xs font-normal text-muted-foreground">（必須）</span> : null}
                  </dt>
                  <dd>
                    {s.kind === "outcome" ? (
                      draft.outcome ? (
                        <Badge variant={outcomeTone(draft.outcome)}>{draft.outcome}</Badge>
                      ) : (
                        <span className="text-sm italic text-muted-foreground">（記載なし）</span>
                      )
                    ) : (
                      <SectionReadValue value={String(draft[s.key])} />
                    )}
                  </dd>
                </div>
              ))}
            </dl>
          ) : (
            // ── DRAFT: editable fields ──
            <Form className="space-y-4" onSubmit={(e) => e.preventDefault()}>
              {SECTIONS.map((s) => {
                const required = REQUIRED_KEYS.has(s.key);
                const value = String(draft[s.key]);
                const isMissing = required && !value.trim();
                if (s.kind === "outcome") {
                  return (
                    <FormField key={s.key} required={required} error={isMissing ? "転帰を選択してください。" : undefined}>
                      <FormLabel>{s.label}</FormLabel>
                      {s.description ? <FormDescription>{s.description}</FormDescription> : null}
                      <FormControl>
                        <Select
                          value={draft.outcome}
                          onChange={(e) => updateSection("outcome", e.target.value)}
                          aria-invalid={isMissing || undefined}
                        >
                          <option value="">選択してください</option>
                          {OUTCOMES.map((o) => (
                            <option key={o} value={o}>
                              {o}
                            </option>
                          ))}
                        </Select>
                      </FormControl>
                    </FormField>
                  );
                }
                return (
                  <Textarea
                    key={s.key}
                    label={
                      <span className="flex items-center gap-1">
                        {s.label}
                        {required ? <span aria-hidden className="text-destructive">*</span> : null}
                        {required ? <span className="sr-only">（必須）</span> : null}
                      </span>
                    }
                    description={s.description}
                    rows={s.rows ?? 3}
                    value={value}
                    aria-invalid={isMissing || undefined}
                    onChange={(e) => updateSection(s.key, e.target.value)}
                  />
                );
              })}
            </Form>
          )}
        </CardContent>
      </Card>

      {/* ── 退院時データ：検査値 / 処方 / 外来予約 ── */}
      <Card className="mb-5">
        <CardHeader className="pb-3">
          <CardTitle as="h2" className="flex items-center gap-2 text-base">
            <IconFlask className="h-4 w-4 text-muted-foreground" aria-hidden />
            退院時データ
          </CardTitle>
          <CardDescription>退院時の主要検査値・処方・次回外来予約。</CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          {/* 退院時 主要検査値 — ReferenceValue flags abnormal by icon+text */}
          <section aria-labelledby="dlabs-h">
            <h3 id="dlabs-h" className="mb-2 flex items-center gap-1.5 text-sm font-semibold text-foreground">
              <IconFlask className="h-4 w-4 text-muted-foreground" aria-hidden />
              退院時 主要検査値
            </h3>
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>検査項目</TableHead>
                  <TableHead className="text-right">測定値（基準値判定）</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {dischargeLabs.map((lab) => (
                  <TableRow key={lab.id}>
                    <TableCell className="font-medium">{lab.name}</TableCell>
                    <TableCell className="text-right">
                      <ReferenceValue
                        className="justify-end"
                        value={lab.value}
                        unit={lab.unit}
                        size="inline"
                        showLabel
                        showRange
                        range={{
                          low: lab.low,
                          high: lab.high,
                          criticalLow: lab.criticalLow,
                          criticalHigh: lab.criticalHigh,
                        }}
                      />
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </section>

          <Separator />

          {/* 退院時処方 */}
          <section aria-labelledby="dmeds-h">
            <h3 id="dmeds-h" className="mb-2 flex items-center gap-1.5 text-sm font-semibold text-foreground">
              <IconPill className="h-4 w-4 text-muted-foreground" aria-hidden />
              退院時処方
            </h3>
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>薬剤</TableHead>
                  <TableHead>用量</TableHead>
                  <TableHead>用法</TableHead>
                  <TableHead className="text-right">日数</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {dischargeMeds.map((m) => (
                  <TableRow key={m.id}>
                    <TableCell className="font-medium">{m.name}</TableCell>
                    <TableCell>{m.dose}</TableCell>
                    <TableCell>{m.freq}</TableCell>
                    <TableCell className="text-right tabular-nums">{m.days}</TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </section>

          <Separator />

          {/* 次回外来予約 */}
          <section aria-labelledby="appt-h">
            <h3 id="appt-h" className="mb-2 flex items-center gap-1.5 text-sm font-semibold text-foreground">
              <IconCalendarClock className="h-4 w-4 text-muted-foreground" aria-hidden />
              次回外来予約
            </h3>
            <MetadataList
              layout="horizontal"
              items={appointments.map((a) => ({
                label: `${formatDate(a.date)} ・ ${a.department}`,
                value: a.note,
              }))}
            />
          </section>
        </CardContent>
      </Card>

      {/* ── 確定・署名 → 追記 (the centerpiece) ── */}
      <Card className="mb-5">
        <CardHeader className="pb-3">
          <CardTitle as="h2" className="flex items-center gap-2 text-base">
            {signed ? (
              <IconLock className="h-4 w-4 text-success" aria-hidden />
            ) : (
              <IconLockOpen className="h-4 w-4 text-muted-foreground" aria-hidden />
            )}
            署名・確定 ／ 追記
          </CardTitle>
          <CardDescription>
            署名・確定すると本文はロックされ、以後は追記でのみ修正できます（追記には記録者・日時・理由が付きます）。
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-5">
          {/* signature audit line */}
          {signed ? (
            <div className="flex flex-col gap-1.5 rounded-lg border border-success-border bg-success-subtle px-3 py-2.5 text-sm">
              <span className="inline-flex items-center gap-1.5 font-medium text-success-subtle-foreground">
                <IconSignature className="h-4 w-4 shrink-0" aria-hidden />
                {signedBy} が署名・確定
              </span>
              <span className="text-xs text-muted-foreground">
                署名日時：{signedAt ? formatDateTime(signedAt) : "—"} ／ 診療科：{patient.department}
              </span>
            </div>
          ) : (
            <p className="text-sm text-muted-foreground">
              まだ署名されていません。必須セクションをすべて記載すると署名できます。
            </p>
          )}

          {/* 指導医 co-sign (only if a resident drafted it) */}
          {signed && RESIDENT_DRAFTING ? (
            <div>
              <h3 className="mb-2 flex items-center gap-1.5 text-sm font-semibold text-foreground">
                <IconStethoscope className="h-4 w-4 text-muted-foreground" aria-hidden />
                指導医の共同署名（上級医承認）
              </h3>
              <p className="mb-2 text-sm text-muted-foreground">
                研修医（{patient.resident}）が作成したサマリです。指導医（{ATTENDING_ID}）の共同署名で正式な記録になります。
              </p>
              <CoSign
                primaryId={CURRENT_USER}
                value={coSign}
                onSign={setCoSign}
                requireReason={false}
                signerLabel="指導医ID"
                attestations={[
                  { id: "review", label: "退院サマリの内容を確認した" },
                  { id: "agree", label: "診断・経過・退院後方針に同意する" },
                ]}
                labels={{
                  sign: "共同署名して承認",
                  signed: "指導医 共同署名 済",
                  signerOf: (id) => `指導医: ${id}`,
                }}
              />
            </div>
          ) : null}

          {/* 追記チェーン (addendum chain) as a Timeline */}
          {signed ? (
            <div>
              <h3 className="mb-2 flex items-center gap-1.5 text-sm font-semibold text-foreground">
                <IconCornerDownRight className="h-4 w-4 text-muted-foreground" aria-hidden />
                追記（addendum）チェーン
              </h3>
              {addenda.length === 0 ? (
                <p className="text-sm italic text-muted-foreground">追記はまだありません。</p>
              ) : (
                <Timeline>
                  {addenda.map((ad, i) => (
                    <TimelineItem key={ad.id} variant="info">
                      <TimelineTime>{formatDateTime(ad.at)}</TimelineTime>
                      <TimelineTitle>
                        追記 {i + 1} ・ {ad.author}
                      </TimelineTitle>
                      <TimelineDescription>
                        <span className="block text-xs font-medium text-foreground">理由：{ad.reason}</span>
                        <span className="mt-0.5 block whitespace-pre-wrap text-foreground">{ad.body}</span>
                      </TimelineDescription>
                    </TimelineItem>
                  ))}
                </Timeline>
              )}
            </div>
          ) : null}
        </CardContent>

        {/* ── アクション ── */}
        <CardFooter className="flex-wrap gap-2 border-t border-border pt-4">
          {!signed ? (
            <>
              <Button variant="outline" type="button">
                下書き保存
              </Button>
              <Button
                variant="success"
                type="button"
                className="ml-auto"
                disabled={!canSign}
                onClick={() => setSignOpen(true)}
              >
                <IconSignature className="mr-1.5 h-4 w-4" aria-hidden />
                署名・確定
              </Button>
            </>
          ) : (
            <>
              <Button variant="outline" type="button">
                <IconPrinter className="mr-1.5 h-4 w-4" aria-hidden />
                印刷 / PDF
              </Button>
              <Button variant="outline" type="button">
                <IconFileText className="mr-1.5 h-4 w-4" aria-hidden />
                紹介状作成
              </Button>
              <Button variant="primary" type="button" className="ml-auto" onClick={() => setAddOpen(true)}>
                <IconPlus className="mr-1.5 h-4 w-4" aria-hidden />
                追記する
              </Button>
            </>
          )}
        </CardFooter>
      </Card>

      {/* ── 署名確認 Dialog ── */}
      <Dialog open={signOpen} onOpenChange={setSignOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>退院サマリを署名・確定しますか？</DialogTitle>
            <DialogDescription>
              署名すると本文は変更不可の法的記録となり、以後の修正は追記（addendum）でのみ可能になります。この操作は取り消せません。
            </DialogDescription>
          </DialogHeader>
          <div className="rounded-lg border border-border bg-muted/40 px-3 py-2.5 text-sm">
            <div className="flex items-center gap-1.5 font-medium text-foreground">
              <IconSignature className="h-4 w-4" aria-hidden />
              署名者：{CURRENT_USER}
            </div>
            <p className="mt-1 text-xs text-muted-foreground">
              署名日時はこの操作の時刻で自動記録されます。
              {RESIDENT_DRAFTING ? " 研修医の作成のため、確定後に指導医の共同署名が必要です。" : ""}
            </p>
          </div>
          <DialogFooter>
            <Button variant="outline" type="button" onClick={() => setSignOpen(false)}>
              キャンセル
            </Button>
            <Button variant="success" type="button" onClick={handleSign} disabled={!canSign}>
              <IconLock className="mr-1.5 h-4 w-4" aria-hidden />
              署名して確定
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ── 追記 Dialog (author + timestamp + reason) ── */}
      <Dialog open={addOpen} onOpenChange={setAddOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>追記（Addendum）</DialogTitle>
            <DialogDescription>
              確定済みのサマリ本文は変更できません。追記は独自の記録者・タイムスタンプ・理由とともに記録の末尾に追加されます。
            </DialogDescription>
          </DialogHeader>
          <div className="mb-1 flex items-center gap-2 rounded-md border border-info-border bg-info-subtle px-3 py-2 text-xs text-info-subtle-foreground">
            <IconLock className="h-4 w-4 shrink-0" aria-hidden />
            <span>
              記録者 <strong>{CURRENT_USER}</strong> ・ {formatDateTime(nowISO())} として追記します。
            </span>
          </div>
          <Form className="space-y-3" onSubmit={(e) => e.preventDefault()}>
            <Textarea
              label="追記の理由"
              description="なぜ追記するのか（例：検査結果の追加、転帰の補足）。"
              rows={2}
              value={addReason}
              onChange={(e) => setAddReason(e.target.value)}
            />
            <Textarea
              label="追記内容"
              rows={4}
              value={addBody}
              onChange={(e) => setAddBody(e.target.value)}
            />
          </Form>
          <DialogFooter>
            <Button variant="outline" type="button" onClick={() => setAddOpen(false)}>
              キャンセル
            </Button>
            <Button variant="primary" type="button" onClick={handleAddAddendum} disabled={!addReason.trim() || !addBody.trim()}>
              <IconPlus className="mr-1.5 h-4 w-4" aria-hidden />
              追記を保存
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  );
}
